#!/usr/bin/env bash # ============================================================ # generate_patches.sh 鈥?Generate real patches from engine source # ============================================================ # Run this on a machine with VS2022, depot_tools, and a fetched # Flutter engine source tree (C:\engine\src). # # Steps: #   1. Pull the engine source matching Flutter 3.44.1 #   2. Generate real diffs by reverting Win10+ API changes #   3. Save patches to engine_patches/{dart-sdk,flutter-engine}/ # # Usage: #   bash tools/generate_patches.sh # ============================================================ set -euo pipefail  ENGINE_SRC="${ENGINE_SRC:-C:/engine/src}" PATCH_DIR="$(cd "$(dirname "$0")/../engine_patches" && pwd)"  echo "=== Generating Win7 patches from engine at $ENGINE_SRC ==="  # --- Patch 1: dart-revert-GetHostNameW --- echo "[1/7] dart: revert GetHostNameW..." cd "$ENGINE_SRC/dart" git log --all --oneline -- runtime/bin/platform_win.cc | head -5 || true echo "  MANUAL: Find and revert the GetHostNameW commit." echo "  git revert <commit-hash> --no-edit" echo "  git format-patch -1 HEAD -o $PATCH_DIR/dart-sdk/"  # --- Patch 2: dart-restore-RtlAddGrowableFunctionTable --- echo "[2/7] dart: restore RtlAddGrowableFunctionTable compat..." echo "  MANUAL: git revert 34213ba60578e46fc2455c5a56b09d9efabc532b --no-edit" echo "  git format-patch -1 HEAD -o $PATCH_DIR/dart-sdk/"  # --- Patch 3: dart-revert-PathCchCombineEx --- echo "[3/7] dart: revert PathCchCombineEx..." echo "  MANUAL: git revert b4574904f9cd0d6f7147950c02ee2447569d0be9 --no-edit" echo "  git format-patch -1 HEAD -o $PATCH_DIR/dart-sdk/"  # --- Patch 4: flutter-engine-disable-impeller --- echo "[4/7] engine: disable Impeller (gn flag, no code diff)" echo "  This is a build-time config only:" echo "  python tools/gn.py --no-enable-impeller" echo "  No patch file change needed (stub kept for documentation)."  # --- Patch 5: flutter-engine-pointer-mouse-fallback --- echo "[5/7] engine: dynamic-load pointer APIs..." echo "  MANUAL: Edit shell/platform/windows/pointer_injector_win32.cc" echo "  MANUAL: Edit shell/platform/windows/flutter_windows_view.cc" echo "  cd $ENGINE_SRC/flutter && git diff > $PATCH_DIR/flutter-engine/0005-embedder-pointer-mouse-fallback.patch"  # --- Patch 6: flutter-engine-thread-naming-compat --- echo "[6/7] engine: dynamic-load SetThreadDescription..." echo "  MANUAL: Edit shell/platform/windows/thread_helper.cc" echo "  cd $ENGINE_SRC/flutter && git diff > $PATCH_DIR/flutter-engine/0006-embedder-thread-naming-compat.patch"  # --- Patch 7: dart-file-ops-fallback --- echo "[7/7] dart: dynamic-load SetFileInformationByHandle..." echo "  MANUAL: Check if runtime/bin/file_win.cc uses SetFileInformationByHandle" echo "  cd $ENGINE_SRC/dart && git diff > $PATCH_DIR/dart-sdk/0007-dart-file-ops-fallback-win7.patch"  echo "" echo "=== Done ===" echo "After generating all patches:" echo "  python tools/apply_patches.py --engine-dir $ENGINE_SRC --dry-run" echo "  python tools/apply_patches.py --engine-dir $ENGINE_SRC"